// components/cases/case-card.tsx
import Link from 'next/link'
import { format } from 'date-fns'
import { ko } from 'date-fns/locale'
import { Card, CardContent } from '@/components/ui/card'
import { BedBadge } from '@/components/cases/bed-badge'
import { StatusBadge } from '@/components/cases/status-badge'
import type { Case } from '@/lib/supabase/types'

interface CaseCardProps { case: Case }

export function CaseCard({ case: c }: CaseCardProps) {
  return (
    <Link href={`/cases/${c.id}`}>
      <Card className="hover:shadow-md transition-shadow cursor-pointer h-full">
        <CardContent className="p-4 flex flex-col gap-2">
          // 상단 행: BedBadge + StatusBadge
          <div className="flex items-center gap-2">
            <BedBadge bedZone={c.bed_zone} bedNumber={c.bed_number} size="sm" />
            <StatusBadge status={c.status} />
          </div>
          // C.C 텍스트
          <p className="font-medium">{c.cc ?? '(C.C 미입력)'}</p>
          // 날짜
          <p className="text-sm text-muted-foreground">
            {format(new Date(c.created_at), 'MM/dd HH:mm')}
          </p>
        </CardContent>
      </Card>
    </Link>
  )
}

// app/(app)/dashboard/page.tsx
import Link from 'next/link'
import { Button } from '@/components/ui/button'
import { CaseCard } from '@/components/cases/case-card'
import { MOCK_CASES } from '@/lib/mock/cases'
import { Plus } from 'lucide-react'

export default function DashboardPage() {
  const recentCases = MOCK_CASES.slice(0, 3)

  return (
    <div className="flex flex-col gap-6 p-4 md:p-8">
      // 페이지 헤더 (데스크탑: 제목 + 우측 버튼)
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">대시보드</h1>
        <Button asChild className="hidden md:flex">
          <Link href="/cases/new"><Plus /> 새 케이스</Link>
        </Button>
      </div>

      // 모바일 전용 대형 CTA (md 이상에서 숨김)
      <Button asChild size="lg" className="w-full text-lg h-16 md:hidden">
        <Link href="/cases/new">새 케이스 시작</Link>
      </Button>

      // 최근 케이스 섹션
      <section>
        <h2 className="text-sm font-medium text-muted-foreground mb-3">최근 케이스</h2>
        if (recentCases.length === 0) {
          // 빈 상태 UI
        } else {
          <div className="grid grid-cols-1 gap-3 md:grid-cols-2 lg:grid-cols-3">
            {recentCases.map(c => <CaseCard key={c.id} case={c} />)}
          </div>
        }
        <Link href="/cases" className="text-sm text-muted-foreground hover:text-foreground mt-3 inline-block">
          전체 목록 보기 →
        </Link>
      </section>
    </div>
  )
}

tasks.description:
시간 표현 파싱 순수 함수를 만들고, 카드 타임라인 UI 테스트용 더미 카드 데이터를 추가한다.

1. lib/time/parse-time-tag.ts 신규 생성
   - parseTimeTag(text: string): { timeTag: string | null, timeOffsetMinutes: number | null }
   - 한국어 패턴: N일 전(N*1440분), N시간 전(N*60분), N분 전(N분), 어제(1440분), 그제(2880분), 오늘(0분)
   - 영어 패턴: N days ago, N hours ago
   - 매칭 없으면 { timeTag: null, timeOffsetMinutes: null } 반환
   - 첫 매칭 패턴의 matched string을 timeTag로 반환

2. lib/mock/cases.ts 수정
   - MOCK_CASE_INPUTS: CaseInput[] 배열 추가 (export)
   - 시간 태그 있는 카드 4개: { id, case_id: MOCK_CASES[0].id, raw_text, time_tag, time_offset_minutes, display_order, created_at }
     예: { raw_text: '3일 전부터 흉통', time_tag: '3일 전', time_offset_minutes: 4320, display_order: 1 }
   - 시간 태그 없는 카드 2개: { time_tag: null, time_offset_minutes: null }
   - MOCK_GUIDE_CONTENT: string — chest-pain 가이드라인 Markdown 샘플 텍스트 (하드코딩)

